/*
  DilAvatar v8 — Görsel Gömülü Erkek Konuşan Avatar
  -------------------------------------------------
  Tek dosya avatar.js olarak kullanılabilir.
  Dış servis, API, sunucu, kütüphane yoktur.
  Avatar görseli bu dosyanın içine base64 olarak gömülüdür.

  Kullanım:
    DilAvatar.mount("avatarHost");
    DilAvatar.speakText("merhaba bugün ingilizce çalışıyoruz", 3200);

  Ayar paneli:
    DilAvatar.mountControlPanel("panelHost");

  Not:
    Gerçek ses dalgasına bağlı lip-sync hedef değildir.
    Metin harflere ayrılır, Türkçe harf tabanlı viseme eşlemesiyle ağız oynatılır.
*/
(function(global){
"use strict";

var AVATAR_IMAGE = "data:image/png;base64,";

var STORAGE_KEY = "DilAvatar.v8.male.settings";

var DEFAULTS = {
  avatar: {
    borderColor: "#2dd4bf",
    bgColor: "#0b1120",
    imageZoom: 1,
    imageX: 0,
    imageY: 0,

    // Görsel 1000x1000 koordinat sistemine oturtulur.
    mouthX: 500,
    mouthY: 548,
    mouthScale: 1,
    mouthWidth: 128,
    mouthHeight: 32,
    mouthRotate: 0,
    mouthOpacity: 0.96,
    mouthColor: "#1f120d",
    lipColor: "#d77b55",
    teethColor: "#ffffff",

    leftEyeX: 408,
    leftEyeY: 386,
    rightEyeX: 592,
    rightEyeY: 386,
    eyeW: 74,
    eyeH: 32,
    eyeStroke: 8,
    eyeCurve: 18,
    eyeLidColor: "#f2a66f",
    eyeLineColor: "#2b160d",

    browVisible: true,
    browOpacity: 1,
    browColor: "#2f160d",
    browWidth: 94,
    browHeight: 22,
    browPeak: 20,
    browStroke: 13,
    leftBrowX: 407,
    leftBrowY: 340,
    rightBrowX: 593,
    rightBrowY: 340,
    leftBrowRotate: -5,
    rightBrowRotate: 5
  }
};

var state = {
  host: null,
  root: null,
  layer: null,
  settings: null,
  mouth: "rest",
  speakingTimer: null,
  blinkTimer: null,
  blinkOffTimer: null,
  thinkingTimer: null,
  isBlinking: false,
  controls: []
};

function clone(obj) {
  return JSON.parse(JSON.stringify(obj));
}

function safeGet(key, fallback) {
  try {
    var v = global.localStorage && global.localStorage.getItem(key);
    return v == null ? fallback : v;
  } catch(e) {
    return fallback;
  }
}

function safeSet(key, value) {
  try {
    if (global.localStorage) global.localStorage.setItem(key, value);
  } catch(e) {}
}

function safeRemove(key) {
  try {
    if (global.localStorage) global.localStorage.removeItem(key);
  } catch(e) {}
}

function loadSettings() {
  state.settings = clone(DEFAULTS);
  var saved = safeGet(STORAGE_KEY, null);
  if (saved) {
    try {
      var parsed = JSON.parse(saved);
      if (parsed && parsed.avatar) Object.assign(state.settings.avatar, parsed.avatar);
    } catch(e) {}
  }
}

function saveSettings() {
  safeSet(STORAGE_KEY, JSON.stringify(state.settings));
}

function cfg() {
  if (!state.settings) loadSettings();
  return state.settings.avatar;
}

function injectCss() {
  if (document.getElementById("dil-avatar-v8-style")) return;
  var style = document.createElement("style");
  style.id = "dil-avatar-v8-style";
  style.textContent = `
    .da8-box{
      --da-border:#2dd4bf;
      width:300px;
      max-width:100%;
      min-width:180px;
      margin:0 auto;
      color:#e5e7eb;
      font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;
      user-select:none;
    }
    .da8-frame{
      width:100%;
      aspect-ratio:1/1;
      position:relative;
      overflow:hidden;
      border-radius:50%;
      border:4px solid var(--da-border);
      background:#0b1120;
      box-shadow:0 18px 40px rgba(0,0,0,.35), inset 0 0 0 1px rgba(255,255,255,.08);
    }
    .da8-layer,.da8-svg,.da8-img{
      position:absolute;
      inset:0;
      width:100%;
      height:100%;
    }
    .da8-img{
      object-fit:cover;
      transform-origin:center center;
      display:block;
      pointer-events:none;
    }
    .da8-actions{
      display:flex;
      gap:8px;
      justify-content:center;
      flex-wrap:wrap;
      margin-top:12px;
    }
    .da8-actions button,.da8-panel button{
      border:0;
      background:#2563eb;
      color:white;
      border-radius:14px;
      padding:10px 14px;
      font-weight:800;
      cursor:pointer;
    }
    .da8-panel{
      max-width:980px;
      background:#0b1120;
      border:1px solid rgba(148,163,184,.28);
      border-radius:18px;
      padding:14px;
      color:#e5e7eb;
      font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;
    }
    .da8-panel h3{margin:0 0 12px;font-size:19px}
    .da8-grid{
      display:grid;
      grid-template-columns:repeat(auto-fit,minmax(230px,1fr));
      gap:12px;
    }
    .da8-card{
      border:1px solid rgba(148,163,184,.25);
      background:#111827;
      border-radius:14px;
      padding:12px;
    }
    .da8-card h4{margin:0 0 8px;color:#93c5fd}
    .da8-row{
      display:grid;
      grid-template-columns:100px 1fr 58px;
      gap:8px;
      align-items:center;
      margin:7px 0;
      font-size:12px;
    }
    .da8-row input[type=range]{width:100%}
    .da8-row output{text-align:right;color:#cbd5e1;font-variant-numeric:tabular-nums}
    .da8-small-actions{
      display:flex;
      flex-wrap:wrap;
      gap:8px;
      margin-top:12px;
    }
    .da8-small-actions button{
      background:#1e293b;
      color:#e5e7eb;
      padding:9px 12px;
    }
    .da8-small-actions button.primary{background:#2563eb;color:#fff}
    .da8-json{
      width:100%;
      min-height:120px;
      margin-top:10px;
      box-sizing:border-box;
      border-radius:12px;
      border:1px solid rgba(148,163,184,.3);
      background:#020617;
      color:#dbeafe;
      padding:10px;
      font:12px ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;
    }
  `;
  document.head.appendChild(style);
}

function render() {
  if (!state.layer) return;
  var c = cfg();
  if (state.root) state.root.style.setProperty("--da-border", c.borderColor);
  state.layer.innerHTML = `
    <img class="da8-img" alt="Erkek avatar"
      src="${AVATAR_IMAGE}"
      onerror="this.outerHTML='<div style=&quot;display:grid;place-items:center;width:100%;height:100%;color:white;background:#7f1d1d;font:700 14px system-ui;text-align:center;padding:20px;box-sizing:border-box&quot;>Avatar görseli yüklenemedi</div>'"
      style="transform:translate(${c.imageX}%, ${c.imageY}%) scale(${c.imageZoom});" />
    ${overlaySvg(c)}
  `;
}

function overlaySvg(c) {
  var blinkDisplay = state.isBlinking ? "block" : "none";
  var brows = c.browVisible ? browSvg(c, "left") + browSvg(c, "right") : "";
  return `
    <svg class="da8-svg" viewBox="0 0 1000 1000" aria-hidden="true">
      <g opacity="${c.browOpacity}">
        ${brows}
      </g>
      <g style="display:${blinkDisplay}">
        ${eyeLidSvg(c, "left")}
        ${eyeLidSvg(c, "right")}
      </g>
      <g transform="translate(${c.mouthX} ${c.mouthY}) rotate(${c.mouthRotate}) scale(${c.mouthScale})"
         opacity="${c.mouthOpacity}">
        ${mouthSvg(c, state.mouth)}
      </g>
    </svg>
  `;
}

function browSvg(c, side) {
  var x = side === "left" ? c.leftBrowX : c.rightBrowX;
  var y = side === "left" ? c.leftBrowY : c.rightBrowY;
  var rot = side === "left" ? c.leftBrowRotate : c.rightBrowRotate;
  var flip = side === "left" ? 1 : -1;
  var w = c.browWidth;
  var h = c.browHeight;
  var p = c.browPeak;
  return `
    <path d="M ${-w/2} ${h/2} C ${-w/4} ${-p}, ${w/4} ${-p}, ${w/2} ${h/2}"
      transform="translate(${x} ${y}) rotate(${rot}) scale(${flip} 1)"
      fill="none" stroke="${c.browColor}" stroke-width="${c.browStroke}" stroke-linecap="round"/>
  `;
}

function eyeLidSvg(c, side) {
  var x = side === "left" ? c.leftEyeX : c.rightEyeX;
  var y = side === "left" ? c.leftEyeY : c.rightEyeY;
  var w = c.eyeW;
  var h = c.eyeH;
  return `
    <ellipse cx="${x}" cy="${y - 2}" rx="${w/2 + 8}" ry="${Math.max(8, h/2)}" fill="${c.eyeLidColor}" opacity=".94"/>
    <path d="M ${x-w/2} ${y} C ${x-w/4} ${y+c.eyeCurve}, ${x+w/4} ${y+c.eyeCurve}, ${x+w/2} ${y}"
      fill="none" stroke="${c.eyeLineColor}" stroke-width="${c.eyeStroke}" stroke-linecap="round"/>
  `;
}

function mouthSvg(c, shape) {
  var w = Number(c.mouthWidth);
  var h = Number(c.mouthHeight);
  var dark = c.mouthColor;
  var lip = c.lipColor;
  var teeth = c.teethColor;

  if (shape === "open") {
    return `
      <ellipse cx="0" cy="0" rx="${w*.46}" ry="${h*.74}" fill="${lip}"/>
      <ellipse cx="0" cy="${h*.04}" rx="${w*.34}" ry="${h*.50}" fill="${dark}"/>
      <path d="M ${-w*.26} ${-h*.30} C ${-w*.08} ${-h*.43}, ${w*.08} ${-h*.43}, ${w*.26} ${-h*.30}" fill="${teeth}" opacity=".95"/>
    `;
  }
  if (shape === "round") {
    return `
      <ellipse cx="0" cy="0" rx="${w*.33}" ry="${h*.66}" fill="${lip}"/>
      <ellipse cx="0" cy="0" rx="${w*.19}" ry="${h*.42}" fill="${dark}"/>
    `;
  }
  if (shape === "wide") {
    return `
      <path d="M ${-w*.56} 0 C ${-w*.25} ${h*.35}, ${w*.25} ${h*.35}, ${w*.56} 0 C ${w*.25} ${h*.55}, ${-w*.25} ${h*.55}, ${-w*.56} 0Z" fill="${lip}"/>
      <path d="M ${-w*.42} ${h*.10} C ${-w*.16} ${h*.30}, ${w*.16} ${h*.30}, ${w*.42} ${h*.10}" fill="none" stroke="${dark}" stroke-width="7" stroke-linecap="round"/>
    `;
  }
  if (shape === "closed") {
    return `
      <path d="M ${-w*.48} 0 C ${-w*.20} ${-h*.18}, ${w*.20} ${-h*.18}, ${w*.48} 0 C ${w*.20} ${h*.22}, ${-w*.20} ${h*.22}, ${-w*.48} 0Z" fill="${lip}"/>
      <path d="M ${-w*.42} 0 C ${-w*.14} ${h*.08}, ${w*.14} ${h*.08}, ${w*.42} 0" fill="none" stroke="${dark}" stroke-width="6" stroke-linecap="round" opacity=".7"/>
    `;
  }
  if (shape === "teeth") {
    return `
      <path d="M ${-w*.48} 0 C ${-w*.20} ${-h*.28}, ${w*.20} ${-h*.28}, ${w*.48} 0 C ${w*.26} ${h*.32}, ${-w*.26} ${h*.32}, ${-w*.48} 0Z" fill="${lip}"/>
      <rect x="${-w*.27}" y="${-h*.14}" width="${w*.54}" height="${h*.24}" rx="7" fill="${teeth}"/>
      <path d="M ${-w*.36} ${h*.08} C ${-w*.12} ${h*.22}, ${w*.12} ${h*.22}, ${w*.36} ${h*.08}" fill="none" stroke="${dark}" stroke-width="5" stroke-linecap="round" opacity=".55"/>
    `;
  }
  return `
    <path d="M ${-w*.45} 0 C ${-w*.18} ${h*.18}, ${w*.18} ${h*.18}, ${w*.45} 0"
      fill="none" stroke="${dark}" stroke-width="8" stroke-linecap="round"/>
    <path d="M ${-w*.28} ${h*.10} C ${-w*.08} ${h*.24}, ${w*.08} ${h*.24}, ${w*.28} ${h*.10}"
      fill="none" stroke="${lip}" stroke-width="6" stroke-linecap="round" opacity=".70"/>
  `;
}

function mount(target) {
  injectCss();
  loadSettings();
  var host = typeof target === "string" ? document.getElementById(target) : target;
  if (!host) throw new Error("DilAvatar.mount: hedef eleman bulunamadı.");

  host.innerHTML = "";
  var root = document.createElement("div");
  root.className = "da8-box";
  var frame = document.createElement("div");
  frame.className = "da8-frame";
  var layer = document.createElement("div");
  layer.className = "da8-layer";
  frame.appendChild(layer);
  root.appendChild(frame);
  host.appendChild(root);

  state.host = host;
  state.root = root;
  state.layer = layer;

  render();
  scheduleBlink();
  return root;
}

function setMouth(shape) {
  if (["rest","open","round","wide","closed","teeth"].indexOf(shape) === -1) shape = "rest";
  state.mouth = shape;
  render();
}

function visemeForChar(ch) {
  ch = String(ch || "").toLocaleLowerCase("tr-TR");
  if ("aeâ".indexOf(ch) >= 0) return "open";
  if ("ou".indexOf(ch) >= 0) return "round";
  if ("ıiüöy".indexOf(ch) >= 0) return "wide";
  if ("mbp".indexOf(ch) >= 0) return "closed";
  if ("fv".indexOf(ch) >= 0) return "teeth";
  if (/\s/.test(ch)) return "rest";
  return "rest";
}

function stop(renderIt) {
  if (state.speakingTimer) clearTimeout(state.speakingTimer);
  state.speakingTimer = null;
  if (state.thinkingTimer) clearInterval(state.thinkingTimer);
  state.thinkingTimer = null;
  state.mouth = "rest";
  if (renderIt !== false) render();
}

function speakText(text, durationMs) {
  stop(false);
  text = String(text || "");
  var chars = Array.prototype.slice.call(text);
  if (!chars.length) {
    setMouth("rest");
    return;
  }
  var per = durationMs ? Number(durationMs) / chars.length : 110;
  if (!isFinite(per)) per = 110;
  per = Math.max(60, Math.min(150, per));

  var i = 0;
  function step() {
    if (i >= chars.length) {
      state.mouth = "rest";
      render();
      state.speakingTimer = null;
      return;
    }
    setMouth(visemeForChar(chars[i]));
    i++;
    state.speakingTimer = setTimeout(step, per);
  }
  step();
}

function blinkOnce() {
  state.isBlinking = true;
  render();
  if (state.blinkOffTimer) clearTimeout(state.blinkOffTimer);
  state.blinkOffTimer = setTimeout(function(){
    state.isBlinking = false;
    render();
  }, 150);
}

function scheduleBlink() {
  if (state.blinkTimer) clearTimeout(state.blinkTimer);
  state.blinkTimer = setTimeout(function(){
    blinkOnce();
    scheduleBlink();
  }, 2500 + Math.random() * 2500);
}

function thinking(on) {
  if (state.thinkingTimer) clearInterval(state.thinkingTimer);
  state.thinkingTimer = null;
  if (!on) {
    setMouth("rest");
    return;
  }
  var flip = false;
  state.thinkingTimer = setInterval(function(){
    flip = !flip;
    setMouth(flip ? "closed" : "rest");
  }, 520);
}

function mountControlPanel(target) {
  injectCss();
  if (!state.settings) loadSettings();
  var host = typeof target === "string" ? document.getElementById(target) : target;
  if (!host) throw new Error("DilAvatar.mountControlPanel: hedef eleman bulunamadı.");
  state.controls = [];

  var panel = document.createElement("div");
  panel.className = "da8-panel";
  panel.innerHTML = `
    <h3>Erkek Avatar Ayarlama Paneli</h3>
    <div class="da8-grid">
      <div class="da8-card" data-card="image"><h4>Görsel</h4></div>
      <div class="da8-card" data-card="mouth"><h4>Ağız</h4></div>
      <div class="da8-card" data-card="eye"><h4>Göz Kırpma</h4></div>
      <div class="da8-card" data-card="brow"><h4>Kaş</h4></div>
    </div>
    <div class="da8-small-actions">
      <button class="primary" data-act="speak">Konuşma test</button>
      <button data-act="blink">Göz test</button>
      <button data-mouth="rest">rest</button>
      <button data-mouth="open">open</button>
      <button data-mouth="round">round</button>
      <button data-mouth="wide">wide</button>
      <button data-mouth="closed">closed</button>
      <button data-mouth="teeth">teeth</button>
      <button data-act="reset">Sıfırla</button>
      <button data-act="export">JSON getir</button>
      <button data-act="import">JSON yükle</button>
    </div>
    <textarea class="da8-json" placeholder="JSON burada görünür / buraya yapıştırılır"></textarea>
  `;
  host.innerHTML = "";
  host.appendChild(panel);

  var image = panel.querySelector('[data-card="image"]');
  var mouth = panel.querySelector('[data-card="mouth"]');
  var eye = panel.querySelector('[data-card="eye"]');
  var brow = panel.querySelector('[data-card="brow"]');

  addRange(image, "imageZoom", "Görsel zoom", .6, 1.8, .01);
  addRange(image, "imageX", "Görsel X %", -30, 30, .1);
  addRange(image, "imageY", "Görsel Y %", -30, 30, .1);

  addRange(mouth, "mouthX", "Ağız X", 250, 750, 1);
  addRange(mouth, "mouthY", "Ağız Y", 350, 760, 1);
  addRange(mouth, "mouthScale", "Ağız ölçek", .25, 2.5, .01);
  addRange(mouth, "mouthWidth", "Ağız genişlik", 20, 240, 1);
  addRange(mouth, "mouthHeight", "Ağız yükseklik", 6, 150, 1);
  addRange(mouth, "mouthRotate", "Ağız açı", -45, 45, 1);
  addRange(mouth, "mouthOpacity", "Ağız opaklık", 0, 1, .01);

  addRange(eye, "leftEyeX", "Sol göz X", 260, 520, 1);
  addRange(eye, "leftEyeY", "Sol göz Y", 250, 560, 1);
  addRange(eye, "rightEyeX", "Sağ göz X", 480, 740, 1);
  addRange(eye, "rightEyeY", "Sağ göz Y", 250, 560, 1);
  addRange(eye, "eyeW", "Kapak genişlik", 20, 160, 1);
  addRange(eye, "eyeH", "Kapak yükseklik", 6, 90, 1);
  addRange(eye, "eyeStroke", "Kapak kalınlık", 1, 26, 1);
  addRange(eye, "eyeCurve", "Kapak eğrisi", -40, 70, 1);

  addCheckbox(brow, "browVisible", "Kaş göster");
  addRange(brow, "browOpacity", "Kaş opaklık", 0, 1, .01);
  addRange(brow, "browWidth", "Kaş genişlik", 20, 180, 1);
  addRange(brow, "browHeight", "Kaş yükseklik", -20, 90, 1);
  addRange(brow, "browPeak", "Kaş tepe", -30, 90, 1);
  addRange(brow, "browStroke", "Kaş kalınlık", 1, 32, 1);
  addRange(brow, "leftBrowX", "Sol kaş X", 250, 520, 1);
  addRange(brow, "leftBrowY", "Sol kaş Y", 180, 500, 1);
  addRange(brow, "rightBrowX", "Sağ kaş X", 480, 750, 1);
  addRange(brow, "rightBrowY", "Sağ kaş Y", 180, 500, 1);
  addRange(brow, "leftBrowRotate", "Sol kaş açı", -60, 60, 1);
  addRange(brow, "rightBrowRotate", "Sağ kaş açı", -60, 60, 1);

  panel.addEventListener("click", function(ev){
    var btn = ev.target.closest("button");
    if (!btn) return;
    var m = btn.getAttribute("data-mouth");
    if (m) setMouth(m);
    var act = btn.getAttribute("data-act");
    var ta = panel.querySelector(".da8-json");
    if (act === "speak") speakText("merhaba bugün ingilizce çalışıyoruz", 3200);
    if (act === "blink") blinkOnce();
    if (act === "reset") {
      state.settings = clone(DEFAULTS);
      safeRemove(STORAGE_KEY);
      saveSettings();
      render();
      updateControls();
    }
    if (act === "export") ta.value = JSON.stringify(state.settings, null, 2);
    if (act === "import") {
      try {
        var data = JSON.parse(ta.value);
        if (data && data.avatar) Object.assign(state.settings.avatar, data.avatar);
        saveSettings();
        render();
        updateControls();
      } catch(e) {
        alert("JSON okunamadı.");
      }
    }
  });

  updateControls();
  return panel;
}

function addRange(parent, key, label, min, max, step) {
  var row = document.createElement("label");
  row.className = "da8-row";
  row.innerHTML = `<span>${label}</span><input type="range" min="${min}" max="${max}" step="${step}" data-key="${key}"><output></output>`;
  parent.appendChild(row);
  var input = row.querySelector("input");
  var output = row.querySelector("output");
  input.addEventListener("input", function(){
    cfg()[key] = Number(input.value);
    saveSettings();
    render();
    updateControls();
  });
  state.controls.push({key:key,input:input,output:output,type:"range"});
}

function addCheckbox(parent, key, label) {
  var row = document.createElement("label");
  row.className = "da8-row";
  row.innerHTML = `<span>${label}</span><input type="checkbox" data-key="${key}"><output></output>`;
  parent.appendChild(row);
  var input = row.querySelector("input");
  var output = row.querySelector("output");
  input.addEventListener("change", function(){
    cfg()[key] = !!input.checked;
    saveSettings();
    render();
    updateControls();
  });
  state.controls.push({key:key,input:input,output:output,type:"checkbox"});
}

function updateControls() {
  if (!state.controls || !state.controls.length) return;
  var c = cfg();
  state.controls.forEach(function(item){
    var v = c[item.key];
    if (item.type === "checkbox") {
      item.input.checked = !!v;
      item.output.textContent = v ? "açık" : "kapalı";
    } else {
      item.input.value = v;
      item.output.textContent = String(Math.round(Number(v)*100)/100);
    }
  });
}

function getSettings() {
  return clone(state.settings || DEFAULTS);
}

function setSettings(data) {
  if (!state.settings) loadSettings();
  if (data && data.avatar) Object.assign(state.settings.avatar, data.avatar);
  saveSettings();
  render();
  updateControls();
}

global.DilAvatar = {
  mount: mount,
  mountControlPanel: mountControlPanel,
  setMouth: setMouth,
  speakText: speakText,
  thinking: thinking,
  stop: function(){ stop(true); },
  blink: blinkOnce,
  visemeForChar: visemeForChar,
  getSettings: getSettings,
  setSettings: setSettings,
  setGender: function(){ return "erkek"; },
  getGender: function(){ return "erkek"; }
};

})(window);
